// ============================================================
// Supabase client — populated automatically via Vercel env vars
// ============================================================

// These values are replaced by Vercel at deploy time via env vars
// You NEVER hardcode keys here — they come from vercel.json env settings
const SUPABASE_URL      = window.ENV_SUPABASE_URL      || '';
const SUPABASE_ANON_KEY = window.ENV_SUPABASE_ANON_KEY || '';

// Inject from env.js (generated by Vercel build or local dev)
// See public/env.js — created by the build script

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

// Helper: get current user or redirect to login
export async function requireAuth(redirectTo = '/login.html') {
  const { data: { session } } = await supabase.auth.getSession();
  if (!session) {
    window.location.href = redirectTo;
    return null;
  }
  return session;
}

// Helper: get current user profile (includes role)
export async function getProfile() {
  const session = await requireAuth();
  if (!session) return null;
  const { data } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', session.user.id)
    .single();
  return data;
}

// Toast notifications
export function toast(message, type = 'info') {
  const container = document.getElementById('toast-container')
    || Object.assign(document.createElement('div'), { id: 'toast-container' });
  if (!document.getElementById('toast-container')) document.body.appendChild(container);

  const el = document.createElement('div');
  el.className = `toast ${type}`;
  const icons = { success: '✅', error: '❌', info: 'ℹ️' };
  el.innerHTML = `<span>${icons[type] || ''}</span><span>${message}</span>`;
  container.appendChild(el);
  setTimeout(() => el.remove(), 4000);
}

// Format date
export function fmtDate(iso) {
  return new Date(iso).toLocaleDateString('pt-BR', { day:'2-digit', month:'short', year:'numeric' });
}

